#!/bin/bash
###############################################################################
#          MTS AEGIS — USB Malware Scanner — Deployment Installer            #
#                      Renato Oliveira / MT-Solutions                        #
#                                                                             #
#  Run as root on a fresh Raspberry Pi OS (Bookworm/Bullseye) or any         #
#  Debian/Ubuntu-based Linux.                                                 #
#                                                                             #
#  What this script does:                                                     #
#    1. Installs system dependencies (ClamAV, Flask, rsync, dosfstools)      #
#    2. Creates the directory structure under /opt/usbscan/                   #
#    3. Deploys all application scripts with correct permissions              #
#    4. Detects USB port hardware paths (interactive)                         #
#    5. Configures passwordless sudo for the three engine scripts             #
#    6. Creates a systemd service (aegis-webui) that starts on boot           #
#    7. Writes a udev rule to auto-trigger scans on USB insertion             #
#    8. Writes clamd.conf + freshclam.conf, enables auto-update              #
#    9. Starts the web UI service                                             #
###############################################################################

set -euo pipefail

# ── Colour helpers ────────────────────────────────────────────────────────────
RED='\033[0;31m'; GREEN='\033[0;32m'; CYAN='\033[0;36m'
YELLOW='\033[1;33m'; BOLD='\033[1m'; RESET='\033[0m'

info()    { echo -e "${CYAN}[AEGIS]${RESET} $*"; }
ok()      { echo -e "${GREEN}[  OK  ]${RESET} $*"; }
warn()    { echo -e "${YELLOW}[ WARN ]${RESET} $*"; }
fail()    { echo -e "${RED}[ FAIL ]${RESET} $*"; exit 1; }
header()  { echo -e "\n${BOLD}${CYAN}━━━  $*  ━━━${RESET}"; }

# ── Root check ────────────────────────────────────────────────────────────────
[ "$(id -u)" -eq 0 ] || fail "This installer must be run as root. Use: sudo bash $0"

header "MTS AEGIS — INSTALLER v4.2"
echo -e "  Target system : $(uname -n) / $(uname -m)"
echo -e "  OS            : $(cat /etc/os-release | grep PRETTY_NAME | cut -d= -f2 | tr -d '\"')"
echo -e "  Date          : $(date)"
echo ""

# ── 1. System dependencies ────────────────────────────────────────────────────
header "STEP 1 — Installing system dependencies"

info "Updating package lists..."
apt-get update -qq || warn "apt-get update had warnings — continuing"

PACKAGES="clamav clamav-daemon rsync dosfstools python3-flask python3-pip"
info "Installing: $PACKAGES"
apt-get install -y -qq $PACKAGES || fail "Package installation failed."
ok "Dependencies installed."

# ── 2. Directory structure ────────────────────────────────────────────────────
header "STEP 2 — Creating directory structure"

mkdir -p /opt/usbscan/logs/archives
mkdir -p /mnt/usbscan
mkdir -p /mnt/usb_safe
mkdir -p /etc/aegis

# Web UI user needs write access to logs
chown -R root:www-data /opt/usbscan
chmod -R 775 /opt/usbscan
chmod 755 /etc/aegis

ok "Directories created."

# ── 3. Deploy application files ───────────────────────────────────────────────
header "STEP 3 — Deploying application files"

