LWwgIiRNTlQiIDI+L2Rldi9udWxsIHx8IHRydWUK

USBSCAN_B64

info "Writing usbcopy.sh..."
cat << 'USBCOPY_B64' | base64 -d > /usr/local/bin/usbcopy.sh

USBCOPY_B64

info "Writing usbformat.sh..."
cat << 'USBFORMAT_B64' | base64 -d > /usr/local/bin/usbformat.sh

USBFORMAT_B64

info "Writing webui.py..."
cat << 'WEBUI_B64' | base64 -d > /opt/usbscan/webui.py

WEBUI_B64

info "Writing aegis-detect-ports..."
cat << 'DETECT_B64' | base64 -d > /usr/local/bin/aegis-detect-ports

DETECT_B64

# Set permissions
chmod +x /opt/usbscan/usbscan.sh
chmod +x /usr/local/bin/usbcopy.sh
chmod +x /usr/local/bin/usbformat.sh
chmod +x /usr/local/bin/aegis-detect-ports
chmod 644 /opt/usbscan/webui.py

ok "All files deployed."

# ── 4. Hardware port detection ────────────────────────────────────────────────
header "STEP 4 — Detecting USB hardware port paths"

info "Launching interactive port detection..."
info "You will be asked to plug a USB drive into each port."
echo ""
/usr/local/bin/aegis-detect-ports || fail "Port detection failed. Re-run installer or run: sudo aegis-detect-ports"
echo ""
ok "Port configuration written to /etc/aegis/ports.conf"

# ── 5. Sudoers configuration ──────────────────────────────────────────────────
header "STEP 5 — Configuring sudo permissions"

# www-data (Flask) needs passwordless sudo for the three engine scripts
cat > /etc/sudoers.d/aegis << 'SUDOERS'
# MTS Aegis — allow Flask web server to invoke engine scripts without password
www-data ALL=(ALL) NOPASSWD: /opt/usbscan/usbscan.sh
www-data ALL=(ALL) NOPASSWD: /usr/local/bin/usbcopy.sh
www-data ALL=(ALL) NOPASSWD: /usr/local/bin/usbformat.sh
# aegis-detect-ports is a root-only tool — no www-data sudo needed
SUDOERS

chmod 440 /etc/sudoers.d/aegis
visudo -c -f /etc/sudoers.d/aegis || fail "Sudoers syntax check failed."
ok "Sudo rules written and validated."

# ── 6. Systemd service ────────────────────────────────────────────────────────
header "STEP 6 — Creating systemd service"

cat > /etc/systemd/system/aegis-webui.service << 'SYSTEMD'
[Unit]
Description=MTS Aegis USB Malware Scanner — Web Interface
After=network.target

[Service]
Type=simple
User=www-data
Group=www-data
WorkingDirectory=/opt/usbscan
ExecStart=/usr/bin/python3 /opt/usbscan/webui.py
Restart=always
RestartSec=5
StandardOutput=journal
StandardError=journal
Environment=PYTHONUNBUFFERED=1

[Install]
WantedBy=multi-user.target
SYSTEMD

systemctl daemon-reload
systemctl enable aegis-webui
ok "Service aegis-webui enabled."

# ── 7. udev rule for auto-scan on USB insertion ───────────────────────────────
header "STEP 7 — Installing udev auto-scan rule"

cat > /etc/udev/rules.d/99-aegis-usb.rules << 'UDEV'
# MTS Aegis — trigger scan when a USB storage device is added
# Match BOTH partition (sda1) and whole-disk (sda) USB devices.
# Some drives are formatted directly on the whole disk with no partition table
# and appear as DEVTYPE=disk — we must catch both cases.
# The usbscan.sh lock file prevents double-firing on multi-event udev bursts.
ACTION=="add", SUBSYSTEMS=="usb", SUBSYSTEM=="block", ENV{DEVTYPE}=="partition", \
    RUN+="/bin/bash -c '/opt/usbscan/usbscan.sh %k > /tmp/usbscan_udev.log 2>&1 &'"
ACTION=="add", SUBSYSTEMS=="usb", SUBSYSTEM=="block", ENV{DEVTYPE}=="disk", \
    RUN+="/bin/bash -c '/opt/usbscan/usbscan.sh %k > /tmp/usbscan_udev.log 2>&1 &'"
UDEV

udevadm control --reload-rules
ok "udev rule installed and reloaded."

# ── 8. ClamAV configuration, signatures, and daemon ──────────────────────────
header "STEP 8 — Configuring ClamAV (daemon + auto-update)"

# Stop BOTH clamav services before touching any config.
# clamav-freshclam is installed by apt and may already be running —
# if it holds the freshclam lock our manual update below will fail.
systemctl stop clamav-daemon    2>/dev/null || true
systemctl stop clamav-freshclam 2>/dev/null || true
sleep 1

# ── 7a. Write clamd.conf ─────────────────────────────────────────────────────
info "Writing /etc/clamav/clamd.conf..."
cat > /etc/clamav/clamd.conf << 'CLAMD_CONF'
# MTS Aegis — ClamAV Daemon Configuration
# Generated by install_aegis.sh

#To reconfigure clamd run #dpkg-reconfigure clamav-daemon

# --- Socket & Permissions ---
LocalSocket /var/run/clamav/clamd.ctl
FixStaleSocket true
LocalSocketGroup clamav
LocalSocketMode 666
User clamav

# --- Performance & Threads ---
MaxThreads 12
MaxConnectionQueueLength 30
ReadTimeout 300
IdleTimeout 60
CommandReadTimeout 60

# --- Logging ---
LogFile /var/log/clamav/clamav.log
LogTime true
LogFileUnlock false
LogFileMaxSize 0
LogSyslog false
LogRotate true

# --- Scan Engine Behavior ---
ScanPE true
ScanOLE2 true
ScanPDF true
ScanHTML true
ScanSWF true
ScanELF true
ScanXMLDOCS true
ScanHWP3 true
ScanMail true
ScanArchive true
OfficialDatabaseOnly false
Bytecode true
BytecodeSecurity TrustSigned

# --- Aggressive Detection Settings ---
AlgorithmicDetection true
PhishingSignatures true
PhishingScanURLs true
HeuristicScanPrecedence true
ExtendedDetectionInfo true
DetectPUA true

# --- USB-Specific Limits ---
MaxScanSize 500M
MaxFileSize 250M
StreamMaxLength 250M
MaxRecursion 30
MaxFiles 50000
MaxDirectoryRecursion 30
MaxScanTime 300000

# --- Archive Safety ---
ArchiveBlockEncrypted false
MaxZipTypeRcg 5M
MaxPartitions 128
MaxIconsPE 200

# --- Filesystem ---
CrossFilesystems true
FollowDirectorySymlinks false
FollowFileSymlinks false

# --- Executable & Script Limits ---
MaxEmbeddedPE 40M
MaxHTMLNormalize 20M
MaxHTMLNoTags 5M
MaxScriptNormalize 10M
PCREMatchLimit 20000
PCRERecMatchLimit 10000
PCREMaxFileSize 250M
CLAMD_CONF

# Ensure socket dir and log dir exist with correct ownership
mkdir -p /var/run/clamav /var/log/clamav
chown clamav:clamav /var/run/clamav /var/log/clamav
ok "clamd.conf written."

# ── 7b. Write freshclam.conf ─────────────────────────────────────────────────
# The default Debian freshclam.conf may have NotifyClamd disabled or pointing
# at a stale path. We write a clean config that:
#   - Updates 4x per day (every 6 hours)
#   - Notifies clamd to hot-reload signatures after each successful update
#     (clamd keeps running — no restart needed)
#   - Logs to a dedicated file
info "Writing /etc/clamav/freshclam.conf..."
cat > /etc/clamav/freshclam.conf << 'FRESHCLAM_CONF'
# MTS Aegis — FreshClam Auto-Update Configuration
# Generated by install_aegis.sh

# Update 4 times per day (every ~6 hours)
Checks 4

# Primary + fallback mirrors
DatabaseMirror database.clamav.org
DatabaseMirror db.local.clamav.net

# Database storage (shared with clamd)
DatabaseDirectory /var/lib/clamav

# Logging
UpdateLogFile /var/log/clamav/freshclam.log
LogTime true
LogVerbose false
LogRotate true

# Notify the running clamd to hot-reload after a successful update.
# Must point to the same clamd.conf that clamd is using.
# This means clamd NEVER needs to be restarted for new signatures to take effect.
NotifyClamd /etc/clamav/clamd.conf

# Safety: scripted updates allow incremental .cdiff patches (faster, less bandwidth)
ScriptedUpdates yes

# The user freshclam runs as
DatabaseOwner clamav
FRESHCLAM_CONF

ok "freshclam.conf written."

# ── 7c. Initial signature fetch ───────────────────────────────────────────────
# Run freshclam once now for the initial database.
# clamav-freshclam.service is stopped so there is no lock conflict.
info "Running freshclam initial signature fetch (may take a few minutes on first run)..."
freshclam --quiet || warn "freshclam reported warnings — check /var/log/clamav/freshclam.log"

# ── 7d. Enable and start both services ───────────────────────────────────────
# clamav-freshclam.service: runs in the background, wakes every 6 hours,
#   fetches new signatures, then calls NotifyClamd to hot-reload clamd.
# clamav-daemon.service: the persistent scan engine.
systemctl enable clamav-freshclam
systemctl start  clamav-freshclam
ok "clamav-freshclam auto-update service enabled and running (updates every 6 hours)."

systemctl enable clamav-daemon
systemctl start  clamav-daemon
ok "ClamAV daemon started with custom config."

# ── 9. Start the web UI ───────────────────────────────────────────────────────
header "STEP 9 — Starting Aegis Web Interface"

systemctl start aegis-webui
sleep 2

if systemctl is-active --quiet aegis-webui; then
    ok "aegis-webui is running."
else
    warn "Service may not have started cleanly. Check: journalctl -u aegis-webui -n 30"
fi

# ── Done ──────────────────────────────────────────────────────────────────────
header "INSTALLATION COMPLETE"

IP=$(hostname -I | awk '{print $1}')
echo ""
echo -e "  ${BOLD}Web Interface:${RESET}  http://${IP}:8080"
echo -e "  ${BOLD}Service status:${RESET} systemctl status aegis-webui"
echo -e "  ${BOLD}Live logs:${RESET}      journalctl -u aegis-webui -f"
echo -e "  ${BOLD}Scan logs:${RESET}      /opt/usbscan/logs/"
echo -e "  ${BOLD}Port config:${RESET}    /etc/aegis/ports.conf"
echo -e "  ${BOLD}Reconfigure ports:${RESET} sudo aegis-detect-ports"
echo ""
echo -e "${GREEN}  MTS AEGIS IS ONLINE. INSERT USB TO BEGIN.${RESET}"
echo ""